const n=`{% block sw_bulk_edit_order_documents %} <div class="sw-bulk-edit-order-documents"> {% block sw_bulk_edit_order_documents_container %} <sw-container columns="1fr" rows="50px" > {% block sw_bulk_edit_order_documents_type %} <mt-checkbox v-for="document in documentTypes" :key="document.id" v-model:checked="value.documentType[document.technicalName]" :label="document.name" :disabled="documents?.disabled || undefined" /> {% endblock %} {% block sw_bulk_edit_order_documents_skip_sent_documents %} <mt-switch v-model="value.skipSentDocuments" :label="$t('sw-bulk-edit.order.status.documents.skipSentDocuments')" :disabled="documents?.disabled || undefined" /> {% endblock %} </sw-container> {% endblock %} </div> {% endblock %}`,{Mixin:d}=Shopware,{Criteria:t}=Shopware.Data,c={template:n,inject:["repositoryFactory"],mixins:[d.getByName("notification")],props:{documents:{type:Object,required:!0},value:{type:Object,required:!0}},data(){return{documentTypes:null}},metaInfo(){return{title:this.$createTitle()}},computed:{documentTypeRepository(){return this.repositoryFactory.create("document_type")},documentTypeCriteria(){const e=new t(1,100);return e.addSorting(t.sort("name","ASC")),e}},created(){this.createdComponent()},methods:{createdComponent(){this.documentTypeRepository.search(this.documentTypeCriteria).then(e=>{this.documentTypes=e,this.documentTypes.forEach(o=>{this.value.documentType[o.technicalName]=null})})}}};export{c as default};
